		r.Route("/mcp", func(r chi.Router) {
			r.Use(flotsammiddleware.Auth(deps.Validator))
			if deps.Config.RateLimitEnabled {
				rl := flotsammiddleware.NewRateLimiter(deps.Config.RateLimitMCP)
				r.Use(rl.Limit)
			}
			r.Handle("/*", placeholderHandler("mcp"))
		})
		slog.Info("router: MCP endpoint enabled at /mcp")
	}

	// Upload endpoint — mandatory auth
	r.Route("/upload", func(r chi.Router) {
		r.Use(flotsammiddleware.Auth(deps.Validator))
		r.Post("/", placeholderHandler("upload"))
	})

	slog.Info("router: initialized",
		"cors_origins", deps.Config.CORSOrigins,
		"mcp_enabled", deps.Config.MCPEnabled,
		"rate_limit_enabled", deps.Config.RateLimitEnabled,
	)

	return r
}

func healthHandler(w http.ResponseWriter, _ *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(map[string]string{
		"status":  "ok",
		"version": version.Version,
	})
}

func placeholderHandler(name string) http.HandlerFunc {
	return func(w http.ResponseWriter, _ *http.Request) {
		http.Error(w, name+" endpoint not yet implemented", http.StatusNotImplemented)
	}
}

func parseCORSOrigins(s string) []string {
	parts := strings.Split(s, ",")
	origins := make([]string, 0, len(parts))
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p != "" {
			origins = append(origins, p)
		}
	}
	return origins
}

package main

import (
	"context"
	"flag"
	"log/slog"
	"os"
	"os/signal"
	"syscall"

	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/joho/godotenv"
	"github.com/riverqueue/river"
	"github.com/riverqueue/river/riverdriver/riverpgxv5"

	"github.com/ketang/flotsam/api/internal/config"
	"github.com/ketang/flotsam/api/internal/db"
	"github.com/ketang/flotsam/api/internal/version"
	"github.com/ketang/flotsam/api/internal/worker"
)

func main() {
	watch := flag.Bool("watch", false, "run continuously, polling for jobs until interrupted")
	once := flag.Bool("once", false, "process pending jobs and exit")
	flag.Parse()

	// Default to --once if neither flag is specified
	if !*watch && !*once {
		*once = true
	}

	// 1. Load .env (no-op if file is absent)
	_ = godotenv.Load()

	// 2. Parse and validate configuration
	cfg, err := config.Load()
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}

	// 3. Configure structured logger
	slog.SetDefault(slog.New(cfg.LogHandler()))
	slog.Info("starting flotsam-worker",
		"version", version.Version,
		"mode", workerMode(*watch),
	)

	// 4. Connect to database
	ctx := context.Background()
	pool, err := db.Connect(ctx, cfg.DatabaseURL)
	if err != nil {
		slog.Error("failed to connect to database", "error", err)
		os.Exit(1)
	}
	defer pool.Close()

	// 5. Create River client with workers registered
	riverClient, err := newRiverClient(pool)
	if err != nil {
		slog.Error("failed to create river client", "error", err)
		os.Exit(1)
	}

	// 6. Start the River client
	if err := riverClient.Start(ctx); err != nil {
		slog.Error("failed to start river client", "error", err)
		os.Exit(1)
	}
	slog.Info("worker: river client started")

	if *watch {
		// Block on SIGINT/SIGTERM, then graceful shutdown
		sigCh := make(chan os.Signal, 1)
		signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
		sig := <-sigCh
		slog.Info("signal received, shutting down", "signal", sig)
	} else {
		// --once: wait briefly for any pending jobs, then stop
		slog.Info("worker: processing pending jobs")
	}

	shutdownCtx, cancel := context.WithTimeout(context.Background(), cfg.ShutdownTimeout)
	defer cancel()

	if err := riverClient.Stop(shutdownCtx); err != nil {
		slog.Error("worker: shutdown error", "error", err)
		os.Exit(1)
	}
	slog.Info("worker: shutdown complete")
}

func newRiverClient(pool *pgxpool.Pool) (*river.Client[*pgxpool.Tx], error) {
	return river.NewClient(riverpgxv5.New(pool), &river.Config{
		Workers: worker.Workers(),
		Queues: map[string]river.QueueConfig{
			river.QueueDefault: {MaxWorkers: 100},
		},
	})
}

func workerMode(watch bool) string {
	if watch {
		return "watch"
	}
	return "once"
}

